mapper.select:


    and biz_type = #{bizType}
    and biz_name like concat('%', #{bizName}, '%')
    and biz_id like concat('%', #{bizId}, '%')
    and op_type = #{opType}
    and success = #{success}
    and oper_user_name like concat('%', #{operUserName}, '%')

        and create_time >= #{params.beginTime}


        and create_time <= #{params.endTime}


order by id desc
